SELECT lp.program_name
FROM loyalty_programs lp
WHERE lp.loyalty_program_id = 1;

SELECT warehouse_name
FROM warehouses
WHERE capacity > (SELECT AVG(capacity) FROM warehouses);

WITH TotalChangesCTE AS (
    SELECT TOTAL_CHANGES() AS total_changes
)
SELECT COS(tc.total_changes) AS cos_total_changes
FROM TotalChangesCTE tc;

SELECT w.warehouse_name, w.capacity, u.role_name, u.description
FROM warehouses w
JOIN user_roles u ON w.warehouse_id = u.role_id;

SELECT ur.role_name, w.warehouse_name
FROM user_roles ur
CROSS JOIN warehouses w;

SELECT role_name, description
FROM user_roles
WHERE role_id > 5;

SELECT role_name 
FROM user_roles 
WHERE role_id = 0 AND TAN(role_id) > 0;

SELECT role_name, description
FROM user_roles
WHERE role_name = 'Sales' OR role_name = 'Admin';

SELECT warehouse_name, SQRT(capacity) AS sqrt_capacity
FROM warehouses
WHERE warehouse_id = 1;

SELECT role_name, description
FROM user_roles
WHERE role_id IN (1, 0);

SELECT role_name, description
FROM user_roles
WHERE role_id = (SELECT MAX(role_id) FROM user_roles);

SELECT role_name 
FROM user_roles 
WHERE role_id % 2 = 0 AND role_id > 0;

SELECT ur.role_name, lp.program_name
FROM user_roles ur
JOIN loyalty_programs lp ON ur.role_id = lp.loyalty_program_id;

SELECT program_name
FROM loyalty_programs
WHERE benefits LIKE '%priority service scheduling%';

SELECT benefits 
FROM loyalty_programs 
WHERE program_name = (SELECT description FROM user_roles WHERE role_name = 'Admin');
